INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Customer Data Platform$q$, $q$Unifies behavioral, transactional, and demographic data into a single customer profile used for segmentation and personalization.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Journey Designer$q$, $q$Visual, trigger-based builder for creating multi-step, cross-channel automated marketing journeys.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Omnichannel Messaging$q$, $q$Sends campaigns across email, SMS, WhatsApp, mobile push, web push, and in-app messages from one platform.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Personalization and Recommendations$q$, $q$A recommendation engine suggests products or content tailored to each user's behavior.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Analytics and Funnels$q$, $q$Dashboards for tracking conversion funnels, cohorts, and campaign performance over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$A/B Testing$q$, $q$Built-in experimentation tools for testing messaging, timing, and journey variations.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$WhatsApp Marketing$q$, $q$Native WhatsApp campaign and automation support, important for markets across Asia, the Middle East, and Latin America.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$SDKs and Integrations$q$, $q$Mobile and web SDKs plus integrations with common data warehouses and marketing tools for data sync.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Deep behavioral segmentation and journey orchestration built for consumer apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Strong multi-channel coverage including WhatsApp, uncommon in many Western-built tools$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Positioned as a more affordable mid-market alternative to Braze or Salesforce Marketing Cloud$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Dedicated onboarding and customer success support for new accounts$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$No published self-serve pricing, requiring a sales conversation for any quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Steeper learning curve for marketers without technical support$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Some users report documentation gaps compared to newer competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Best suited to consumer-scale user bases, less cost-effective for very small teams$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$What is WebEngage used for?$q$, $q$WebEngage is used by consumer brands to unify customer data and run automated, personalized marketing campaigns across email, SMS, WhatsApp, push, and in-app channels.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$How much does WebEngage cost?$q$, $q$WebEngage does not publish pricing publicly. Cost is quoted individually based on usage such as monthly active users and message volume, so you need to request a demo for a price.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Does WebEngage offer a free trial?$q$, $q$WebEngage does not advertise a public self-serve free tier; a trial or proof-of-concept can typically be arranged by contacting its sales team.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$What channels does WebEngage support?$q$, $q$WebEngage supports email, SMS, WhatsApp, mobile push, web push, in-app messages, and on-site personalization widgets.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Who are WebEngage's main competitors?$q$, $q$WebEngage is most often compared to MoEngage, CleverTap, Braze, and Salesforce Marketing Cloud.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Is WebEngage suitable for small businesses?$q$, $q$WebEngage is generally aimed at growth-stage and larger consumer tech companies with meaningful user volume rather than very small businesses, given its custom, sales-led pricing.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Does WebEngage support WhatsApp marketing?$q$, $q$Yes, native WhatsApp campaigns and automation are a core part of the platform's omnichannel offering.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Where is WebEngage headquartered?$q$, $q$WebEngage is headquartered in Mumbai, India, with additional offices in India and international hubs such as Dubai.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$E-commerce retention marketing$q$, $q$Automating cart abandonment, browse abandonment, and win-back campaigns across email, push, and WhatsApp.$q$, $q$e-commerce and D2C brands$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Edtech and fintech onboarding automation$q$, $q$Guiding new users through activation and feature adoption with triggered, behavior-based journeys.$q$, $q$edtech and fintech product teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Media, OTT, and gaming engagement$q$, $q$Re-engaging inactive users and promoting new content or in-app events through personalized push and in-app messaging.$q$, $q$media, OTT, and gaming companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$Custom Plan$q$, $q$Contact sales for a quote$q$, $q$Custom, based on usage$q$, NULL, $q$["Customer data platform","Journey designer","Omnichannel messaging across email, SMS, WhatsApp, push, and in-app","Personalization and recommendations","Analytics and reporting","Dedicated onboarding support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$overview$q$, $q$What Is WebEngage$q$, 2, ARRAY[$q$WebEngage is a customer engagement and retention platform founded in 2011 and headquartered in Mumbai, India. It was built for consumer-facing companies that need to turn raw user behavior into personalized, automated marketing across many channels at once.$q$, $q$The platform combines a customer data layer with a visual journey builder, letting teams define triggers such as a cart abandonment or an app install, and then route users through branching, multi-step campaigns that adjust based on their behavior.$q$, $q$WebEngage is used heavily by e-commerce, edtech, fintech, gaming, and media companies across India, Southeast Asia, the Middle East, and Latin America, where it competes with MoEngage, CleverTap, and larger enterprise suites like Braze.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$WebEngage's journey designer lets marketers build automated, multi-channel campaigns without writing code, combining email, SMS, WhatsApp, mobile push, web push, in-app messages, and on-site widgets in a single flow.$q$, $q$A built-in analytics layer tracks funnels, cohorts, and campaign-level metrics, while an A/B testing engine and a recommendation engine help teams optimize messaging and personalize product or content suggestions.$q$, $q$Native WhatsApp support is a notable differentiator compared to many Western-built engagement platforms, reflecting WebEngage's strength in markets where WhatsApp is a primary customer communication channel.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('99f73517-cbd3-40ff-94a7-89a7c44a0b54', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WebEngage does not publish self-serve pricing on its website. Instead, the pricing page routes prospects to a demo request, and a Marketing Automation Expert works out a custom quote.$q$, $q$Cost is typically driven by factors such as monthly active users or contacts reached, message volume across channels, and which features, such as advanced personalization or premium support, are included.$q$, $q$This sales-led pricing model makes WebEngage harder to comparison-shop against competitors with transparent tiers, though it also allows contracts to be tailored to a company's specific scale and channel mix.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Visual Canvas with Full CSS Control$q$, $q$Build custom, responsive layouts visually while Webflow outputs clean, semantic HTML and CSS.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Built-in CMS (Collections)$q$, $q$Dynamic content management for blogs, directories, and other structured content types.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Ecommerce$q$, $q$Product catalogs, cart, and checkout tools for running an online store directly on Webflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Global CDN Hosting$q$, $q$Built-in hosting and content delivery included with every Site plan.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Interactions and Animations$q$, $q$Visual tools for scroll-based, hover, and click-triggered animations without JavaScript.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$AI-Assisted Site Building$q$, $q$AI credits and tools bundled into Workspace plans for generating layouts and content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Custom Code and Code Components$q$, $q$Ability to embed custom code or reusable code-based components for advanced functionality.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Localization$q$, $q$Tools for building and managing multilingual versions of a site from one project.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Produces clean, semantic HTML and CSS instead of bloated builder markup$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Far more design flexibility than Wix, Squarespace, or Webnode$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Strong CMS for blogs, directories, and content-heavy marketing sites$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Reliable built-in hosting on a global CDN$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Large ecosystem of templates and a professional community of agencies and freelancers$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Pricing structure, combining site plans, workspace seats, and bandwidth or CMS add-ons, can get expensive at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Steeper learning curve than simple drag-and-drop builders$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Ecommerce functionality is less mature than dedicated platforms like Shopify$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Fully exporting a site's design and CMS content to leave the platform is difficult$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Is Webflow free to use?$q$, $q$Webflow offers a free Starter Site plan with limited pages and a Webflow-hosted subdomain, but a paid plan is needed for a custom domain and most advanced features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$How much does Webflow cost in 2026?$q$, $q$After the May 2026 pricing update, Site plans start around 15 dollars a month for Basic and 25 dollars a month for Premium when billed annually, with Enterprise available at custom pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$What changed with Webflow's May 2026 pricing update?$q$, $q$Webflow consolidated its old CMS and Business site plans into a single Premium plan, introduced a new Team plan, and began bundling AI credits into all Workspace plans.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Can I use Webflow without knowing how to code?$q$, $q$Yes, Webflow is designed as a no-code visual builder, though it also supports custom code for teams that want more control.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Does Webflow support ecommerce?$q$, $q$Yes, Webflow Ecommerce provides product catalogs, cart, and checkout, though it is generally less feature-rich than dedicated ecommerce platforms.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Can I add custom code to a Webflow site?$q$, $q$Yes, Webflow supports embedded custom code and code components for functionality beyond the visual builder.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$How is Webflow different from WordPress?$q$, $q$Webflow is a hosted, visual, no-code platform with built-in hosting and CMS, while WordPress is open-source software that typically requires separate hosting, plugins, and more technical maintenance.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Who is Webflow best for?$q$, $q$Webflow is best suited to design agencies, marketing teams, and freelance designers who want strong visual control and a built-in CMS without managing custom code and infrastructure.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Agency client websites$q$, $q$Agencies design and deliver fully custom, responsive client sites without hand-coding every project.$q$, $q$digital design and marketing agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Marketing sites with a blog and CMS$q$, $q$Startups and marketing teams manage a company site alongside a dynamic, content-managed blog.$q$, $q$startups and in-house marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Ecommerce storefronts$q$, $q$Small to mid-size retailers run a design-forward online store using Webflow's built-in ecommerce tools.$q$, $q$small to mid-size online retailers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Starter$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Webflow-hosted subdomain","Limited static pages","Basic CMS access","Visual designer access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Basic$q$, $q$$15/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["Custom domain support","300 static pages","Basic hosting and forms"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Premium$q$, $q$$25/month billed annually ($39/month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["300 static pages","20,000 CMS items across up to 40 collections","50GB bandwidth","Code components","Site search","Form file upload"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Team$q$, $q$$2,500/month$q$, $q$Annual contract$q$, NULL, $q$["10 seats included","100 CMS collections","Localization","AEO agents","Publishing workflows"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$Enterprise$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Advanced security and SSO","Dedicated support and SLAs","Custom limits and contract terms"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$overview$q$, $q$What Is Webflow$q$, 2, ARRAY[$q$Webflow is a visual website builder founded in 2012 and based in San Francisco, California, built around the idea that designers should be able to build production-ready sites visually without sacrificing clean, semantic code underneath.$q$, $q$Instead of locking designs into a proprietary rendering engine, Webflow outputs real HTML and CSS, which is one reason it is popular with agencies and design-led marketing teams that care about performance and long-term flexibility.$q$, $q$The platform pairs its visual canvas with a built-in CMS, global hosting, and, more recently, AI-assisted tools for generating and editing site content and layouts.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Webflow's core is a visual canvas with full control over CSS properties, so designers can build fully custom layouts, interactions, and animations without writing code, while developers can still drop in custom code or code components where needed.$q$, $q$The built-in CMS, organized as Collections, supports content-heavy sites such as blogs, directories, and marketing resource hubs, with dynamic templates that update automatically as content changes.$q$, $q$Webflow Ecommerce adds product catalogs, cart, and checkout, and the platform includes localization tools for multilingual sites, forms, site search, and hosting on a global content delivery network.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('33552c2c-cd73-4391-9fd5-c7a4f0df8e9e', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Webflow overhauled its pricing in May 2026, replacing its older CMS and Business site tiers with a single Premium plan and simplifying the overall lineup to Starter, Basic, Premium, and Enterprise.$q$, $q$The Basic plan starts at around 15 dollars per month billed annually for simpler marketing sites, while Premium, at around 25 dollars per month billed annually, adds CMS collections, site search, and higher bandwidth and page limits.$q$, $q$On top of Site plans, Workspace seats, Full, Limited, and Free, are billed separately and control collaborator access, and a new Team plan bundles seats, CMS collections, and publishing workflows for organizations that need more structure than self-serve plans provide.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Instant Disposable URLs and Email Addresses$q$, $q$Generates a unique URL and email address immediately, with no signup required for basic use.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Live Request Inspector$q$, $q$Displays headers, body, query parameters, and timing for every captured request in real time.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Custom Response Simulation$q$, $q$Lets a URL respond with a configured status code, headers, and body to mimic a real API endpoint.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Custom Actions (Pro)$q$, $q$Scripting feature for transforming, forwarding, or reacting to incoming requests programmatically.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Request History and Export$q$, $q$Stores request history up to plan limits, with CSV export available on paid tiers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Team and Multi-User Support$q$, $q$Enterprise plans add multi-user access and SAML SSO for shared team use.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Open-Source Self-Hosting$q$, $q$An MIT-licensed version can be self-hosted with Docker for teams with data-residency needs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$API Access$q$, $q$Programmatic access for integrating Webhook.site capture and inspection into automated test suites.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Free, instant, and requires no signup for basic use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Open-source and self-hostable for teams with data-residency needs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Simple, fast interface purpose-built for webhook and API debugging$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Custom Actions let Pro users script real webhook logic, not just view requests$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Free tier data expires after 7 days and caps at only 50 requests per URL$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Not a full API mocking or production webhook-delivery platform$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Advanced features like custom domains and SSO require the paid Enterprise tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$No built-in retry, queueing, or delivery-guarantee features for production traffic$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$What is Webhook.site used for?$q$, $q$It is used to instantly capture and inspect incoming HTTP requests, webhooks, and emails, most often while integrating with or debugging a third-party API.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Is Webhook.site free?$q$, $q$Yes, the core inspection feature is free, with a limit of 50 stored requests per URL and 7-day data retention on the free plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$How long does data stay on Webhook.site?$q$, $q$On the free plan, URLs and their captured data are automatically deleted after 7 days; paid plans offer URLs that do not expire.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Can Webhook.site be self-hosted?$q$, $q$Yes, an open-source, MIT-licensed version is available on GitHub and can be self-hosted using Docker.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Is it safe to send sensitive data to Webhook.site?$q$, $q$The hosted free and Pro tiers are intended for testing rather than sensitive production data; teams with strict data requirements often use the self-hosted open-source version instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$What does the Pro plan add?$q$, $q$Pro raises request limits, adds Custom Actions scripting, CSV export, and URLs that never expire, for 27 dollars per month.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$What are alternatives to Webhook.site?$q$, $q$Common alternatives include Beeceptor and Hookdeck, which offer similar request inspection and, in some cases, production-grade webhook delivery features.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Does Webhook.site support custom domains?$q$, $q$Custom domain support for URLs and emails is available on the Enterprise plan.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Testing third-party webhook integrations$q$, $q$Capturing and inspecting webhook payloads from services like Stripe, GitHub, or Shopify during integration work.$q$, $q$backend developers integrating third-party APIs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$API and email debugging during QA$q$, $q$Verifying that an application sends the correct requests or emails during manual or automated testing.$q$, $q$QA engineers and testers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Prototyping webhook-driven workflows$q$, $q$Using Custom Actions to simulate and script how an internal system should react to incoming webhook data.$q$, $q$developers building internal automation and integrations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["1 active URL and email pair","50 stored requests per URL","Data automatically deleted after 7 days","Live request inspector"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Pro$q$, $q$$27/month ($270/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 50 custom URLs and 5 schedules","Unlimited requests with 10,000-request history","Custom Actions workflow automation","URLs that never expire","CSV export","Email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$Enterprise$q$, $q$$69/month ($699/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited URLs and schedules","100,000-request history","Custom domain support for URLs and emails","SAML SSO and multi-user support","Priority support and dedicated queue resources"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$overview$q$, $q$What Is Webhook.site$q$, 2, ARRAY[$q$Webhook.site is a lightweight developer tool that gives you an instant, disposable URL and email address for capturing and inspecting incoming HTTP requests, webhooks, and emails.$q$, $q$It was built by developer Simon Fredsted and is offered both as a hosted cloud service at webhook.site and as an open-source, MIT-licensed project that can be self-hosted with Docker.$q$, $q$Developers use it as a fast alternative to spinning up a local server or tunneling tool whenever they need to see exactly what an external service, such as a payment processor or a source-control platform, sends in a webhook payload.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core feature is the live request inspector, which shows full headers, body content, query parameters, and timing for every request or email sent to a generated URL or address, updating in real time in the browser.$q$, $q$Custom response configuration lets a URL act as a mock API endpoint, returning a chosen status code, headers, and body, which is useful for testing how another system handles different responses.$q$, $q$The Pro-tier Custom Actions feature adds scripting so incoming requests can be transformed, forwarded, or reacted to programmatically, moving Webhook.site beyond pure inspection into lightweight webhook processing.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Webhook.site is free to use for quick testing, with each free URL limited to 50 stored requests and automatic data deletion after 7 days.$q$, $q$The Pro plan costs 27 dollars per month or 270 dollars per year and raises limits to up to 50 custom URLs, unlimited requests with a 10,000-request history, Custom Actions, CSV export, and URLs that no longer expire.$q$, $q$The Enterprise plan costs 69 dollars per month or 699 dollars per year and adds unlimited URLs and schedules, a 100,000-request history, custom domain support, SAML SSO, multi-user support, and priority support.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Live and Automated Webinars$q$, $q$Supports both real-time live webinars and, via bundled EverWebinar, fully automated evergreen replays.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Built-in Registration and Thank-You Pages$q$, $q$Customizable pages for capturing registrants and confirming sign-ups without a separate landing page tool.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Email and SMS Reminder Automation$q$, $q$Automated reminder sequences sent by email and SMS ahead of and during scheduled webinars.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Live Chat, Polls, and Surveys$q$, $q$Real-time audience interaction tools for engagement and moderation during live sessions.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Video Injections and Offers$q$, $q$Plays pre-recorded video segments as if live and displays time-limited purchase offers during the presentation.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Multi-Host Support$q$, $q$Multiple presenters can co-host a session, with host limits increasing on higher-tier plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Social Media Simulcasting$q$, $q$Streams webinars simultaneously to Facebook and YouTube alongside the WebinarJam room.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$EverWebinar Integration$q$, $q$Bundled on Basic and higher plans, enabling fully automated evergreen webinar funnels.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$All-in-one webinar funnel combining registration, reminders, the live event, and sales offers in one tool$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Automated or evergreen webinars available via bundled EverWebinar on most plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Supports large live audiences up to 5,000 attendees on the top tier$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$30-day money-back guarantee plus a low-cost 14-day trial$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Interface and design feel dated compared to newer webinar tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Pricing scales quickly with attendee count and number of hosts$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Session length caps, from 1 to 4 hours depending on plan, can be restrictive for long-form training$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Key features like EverWebinar and more hosts require moving to mid or higher tiers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$What is WebinarJam used for?$q$, $q$WebinarJam is used to host live and automated webinars for product launches, sales presentations, and online course delivery, with built-in registration and marketing tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$How much does WebinarJam cost?$q$, $q$Paid plans start at 39 dollars per month billed annually for the Starter tier and scale up to 379 dollars per month billed annually for the Enterprise tier, based mainly on attendee capacity.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Does WebinarJam include automated webinars?$q$, $q$Yes, its companion product EverWebinar for automated evergreen webinars is bundled into the Basic plan and above.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Is there a free trial?$q$, $q$WebinarJam offers a 14-day trial for 1 dollar rather than a fully free tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$How many attendees can WebinarJam handle?$q$, $q$Attendee capacity ranges from 100 on the Starter plan up to 5,000 on the Enterprise plan.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$What is the difference between WebinarJam and EverWebinar?$q$, $q$WebinarJam hosts live, real-time webinars, while EverWebinar plays fully automated, pre-recorded webinars on a repeating schedule that can simulate live chat activity.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Who makes WebinarJam?$q$, $q$WebinarJam is built by Genesis Digital, a company whose first product was WebinarJam and which also makes Kartra.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$What are alternatives to WebinarJam?$q$, $q$Common alternatives include Zoom Webinar, Demio, and WebinarNinja.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Course launch webinars$q$, $q$Running scheduled live webinars to sell an online course or coaching program with built-in registration and offer tools.$q$, $q$online course creators and coaches$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Product demo and sales webinars$q$, $q$Hosting live product demonstrations for prospects as part of a B2B sales process.$q$, $q$SaaS and agency sales teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Evergreen automated webinar funnels$q$, $q$Using EverWebinar to run always-on, automated replays that convert traffic into leads and sales without live hosting.$q$, $q$digital marketers running always-on funnels$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Starter$q$, $q$$39/month billed annually ($49/month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 100 attendees","1 host","1-hour max session","1 additional team member","Live chat and registration pages"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Basic$q$, $q$$79/month billed annually ($99/month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 500 attendees","2 hosts","2-hour max session","5 additional team members","Includes EverWebinar"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Professional$q$, $q$$229/month billed annually ($299/month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 2,000 attendees","4 hosts","3-hour max session","10 additional team members","Includes EverWebinar"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$Enterprise$q$, $q$$379/month billed annually ($499/month billed monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 5,000 attendees","6 hosts","4-hour max session","25 additional team members","Includes EverWebinar"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$overview$q$, $q$What Is WebinarJam$q$, 2, ARRAY[$q$WebinarJam is a browser-based webinar hosting platform built by Genesis Digital, a company founded in 2013 whose first product was WebinarJam, alongside its later product Kartra.$q$, $q$Unlike a plain video-conferencing tool, WebinarJam is built specifically around the webinar-as-sales-funnel model, bundling registration pages, reminder automation, and in-webinar sales tools into one product.$q$, $q$It supports both live webinars and, via its companion product EverWebinar included on most paid plans, fully automated evergreen webinars that replay on a schedule.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every plan includes customizable registration and thank-you pages, automated email and SMS reminder sequences, live chat and moderation tools, polls and surveys, and a built-in whiteboard for presentations.$q$, $q$Sales-focused features include live offer displays that let presenters show a time-limited purchase button during the webinar, and video injections that play pre-recorded segments seamlessly within a live session.$q$, $q$Higher tiers add more hosts, longer maximum session lengths, more team member seats, and support for larger attendee counts, up to 5,000 on the top Enterprise plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5fb51e1c-1cc8-4be3-ad0c-336f15ecc8c3', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WebinarJam offers a 14-day trial for 1 dollar, followed by four paid tiers priced primarily by attendee capacity: Starter, Basic, Professional, and Enterprise.$q$, $q$Annual billing runs roughly 20 percent cheaper than monthly billing across all tiers, and every paid plan carries a 30-day money-back guarantee.$q$, $q$EverWebinar, the automated webinar companion product, is bundled into the Basic tier and above, so businesses that need evergreen funnels generally need at least the second-lowest plan.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Drag-and-Drop Visual Editor$q$, $q$A beginner-friendly editor for building pages without coding.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Free Plan with Webnode Subdomain$q$, $q$Publish a site for free on a Webnode subdomain with basic templates and Webnode branding.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Multilingual Website Support$q$, $q$Manage a single site's content across multiple languages from one dashboard.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Industry-Specific Templates$q$, $q$Pre-built templates organized by business type and use case.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Built-in Ecommerce$q$, $q$A lightweight store module for selling a limited catalog of products with integrated payments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Blogging and Contact Forms$q$, $q$Native blogging tools and customizable contact forms for lead capture.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Basic SEO Tools$q$, $q$On-page SEO settings for titles, descriptions, and metadata.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Mobile-Responsive Designs$q$, $q$Templates automatically adapt to desktop, tablet, and mobile screens.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Low starting price compared to Wix, Squarespace, and Webflow$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Free plan available with no time limit$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Strong built-in multilingual site support$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Simple, beginner-friendly editor$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Backed by team.blue, a large established European hosting group$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Design flexibility is limited compared to Webflow or Wix$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Free and lower tiers carry Webnode branding and limited storage or bandwidth$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Ecommerce features are basic and not suited for larger catalogs$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Fewer third-party app or integration options than larger competitors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Is Webnode free?$q$, $q$Yes, Webnode offers a free plan with a Webnode subdomain and Webnode branding, though a paid plan is needed for a custom domain and more features.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$How much does Webnode cost?$q$, $q$Paid plans commonly start around 5.50 dollars per month and range up to around 26.50 dollars per month for the highest tier, billed annually.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Does Webnode support multiple languages on one site?$q$, $q$Yes, multilingual site management is one of Webnode's core features, letting one site serve content in several languages.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Can I sell products with Webnode?$q$, $q$Yes, higher-tier plans include a lightweight ecommerce module suited to a limited product catalog.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Who owns Webnode?$q$, $q$Webnode has been part of team.blue, a pan-European digital services group headquartered in Ghent, Belgium, since 2020.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$How does Webnode compare to Wix?$q$, $q$Webnode is generally cheaper and simpler than Wix but offers less design flexibility and a smaller app ecosystem.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Can I use a custom domain on Webnode?$q$, $q$Yes, custom domain support is available starting on Webnode's paid plans.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Is Webnode good for beginners?$q$, $q$Yes, its drag-and-drop editor and templates are designed to be approachable for users with no coding or design experience.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Personal and portfolio websites$q$, $q$Individuals build a simple personal site or portfolio without hiring a developer.$q$, $q$freelancers and individuals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Small local business sites$q$, $q$Small businesses create a professional brochure site with contact forms and basic SEO.$q$, $q$small businesses and service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Simple multilingual online stores$q$, $q$Small businesses sell a limited product catalog across multiple language markets from one site.$q$, $q$small businesses selling across multiple European markets$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Free$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["Webnode subdomain","Webnode branding","Limited storage","Basic templates"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Limited$q$, $q$~$5.50/month billed annually$q$, $q$Annual$q$, NULL, $q$["Custom domain support","Ads removed","Increased storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Mini$q$, $q$~$10/month billed annually$q$, $q$Annual$q$, NULL, $q$["More storage and bandwidth","Email accounts","Improved SEO tools"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Standard$q$, $q$~$16.90/month billed annually$q$, $q$Annual$q$, NULL, $q$["Ecommerce tools","Payment gateway integration","Larger product catalog"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$Profi$q$, $q$~$26.50/month billed annually$q$, $q$Annual$q$, NULL, $q$["Priority support","Advanced ecommerce and marketing tools","Highest storage and bandwidth tier"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$overview$q$, $q$What Is Webnode$q$, 2, ARRAY[$q$Webnode is a cloud-based website builder that launched in 2008, originally as Webnode AG in Switzerland, with its main development and operations base in Brno, Czech Republic.$q$, $q$In 2020 Webnode became part of team.blue, a large pan-European digital services group headquartered in Ghent, Belgium, that owns several hosting and domain brands across the continent.$q$, $q$The platform is positioned as a budget-friendly alternative to Wix and Squarespace, particularly known for strong multilingual site support that appeals to its large European and Latin American user base.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Webnode's visual drag-and-drop editor uses pre-built, industry-specific templates, making it straightforward for non-technical users to launch a site quickly.$q$, $q$A standout feature is multilingual site management, letting a single site serve content in multiple languages from one dashboard rather than requiring separate installations.$q$, $q$The platform also includes blogging tools, contact forms, basic SEO settings, and a lightweight ecommerce module suited to a limited product catalog with integrated payment gateways.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Webnode offers a free plan that includes a Webnode subdomain, Webnode branding, and limited storage, with no time limit on use.$q$, $q$Paid tiers commonly cited include Limited around 5.50 dollars per month, Mini around 10 dollars per month, Standard around 16.90 dollars per month, and Profi around 26.50 dollars per month, generally billed annually for the lowest rate.$q$, $q$Higher tiers progressively add custom domain support, more storage and bandwidth, and ecommerce features, with exact pricing varying somewhat by region and currency.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('46a8e7ec-2b99-40e2-adca-8f81f3b71e57', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$ArchiveWeb.page$q$, $q$Browser extension and desktop app for capturing interactive web pages as you browse.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Browsertrix$q$, $q$Cloud-based crawling service for archiving entire websites at scale.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$ReplayWeb.page$q$, $q$Serverless, browser-based viewer for replaying archived web content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$pywb$q$, $q$Python library for web archive replay, used to power server-side archive viewing.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$WACZ Open Archive Format$q$, $q$An open standard file format for packaging and sharing web archives.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$High-Fidelity Interactive Capture$q$, $q$Records JavaScript-rendered content, video, audio, and user interactions, not just static HTML.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Self-Hosting and Open-Source Licensing$q$, $q$Core tools can be self-hosted or run client-side, avoiding dependence on a hosted service.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Collections and Sharing$q$, $q$Tools for organizing archived pages into collections that can be shared or published.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Captures fully interactive, JavaScript-heavy pages rather than static snapshots$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Core tools are free, open-source, and self-hostable$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$The WACZ format provides an open, portable standard for archived content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Browsertrix offers scalable, managed crawling for teams that need it$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Trusted by libraries, journalists, and legal or compliance teams for evidentiary-quality archives$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Browsertrix's paid tiers are needed for large-scale or automated crawling$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Tools are aimed at technical or archival users, less approachable for casual users than a general-purpose archive site$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Self-hosting the more advanced crawling infrastructure requires technical setup$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Smaller company and community than major commercial archiving vendors$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$What is Webrecorder used for?$q$, $q$Webrecorder is used to capture, preserve, and replay interactive copies of web pages, commonly for legal evidence, research, journalism, and library archiving.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Is Webrecorder free?$q$, $q$Its core tools, ArchiveWeb.page, ReplayWeb.page, and pywb, are free and open source; the hosted Browsertrix crawling service has paid plans starting around 30 dollars per month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$What is the difference between ArchiveWeb.page and Browsertrix?$q$, $q$ArchiveWeb.page is a browser tool for manually capturing pages as you browse them, while Browsertrix is a cloud crawling service for automatically archiving entire websites at scale.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$What is the WACZ file format?$q$, $q$WACZ is an open, standardized file format that Webrecorder maintains for packaging and sharing web archive collections.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Can Webrecorder capture JavaScript-heavy or interactive pages?$q$, $q$Yes, its tools are specifically built to capture dynamic, script-driven content, video, audio, and user interactions, not just static HTML.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Is Webrecorder open source?$q$, $q$Yes, its core tools are open source, and most can be self-hosted or run entirely client-side.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$How does Webrecorder compare to generic web archiving services?$q$, $q$Webrecorder focuses on high-fidelity, interactive capture and open standards like WACZ, making it better suited to evidentiary or research-grade archiving than simple crawl-based snapshot tools.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Who uses Webrecorder?$q$, $q$Librarians, digital archivists, journalists, researchers, and legal or compliance teams are among its most common users.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Legal and compliance web evidence capture$q$, $q$Capturing an interactive, verifiable record of a web page for use as legal evidence or compliance documentation.$q$, $q$legal teams and compliance professionals$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Library and institutional web preservation$q$, $q$Archiving websites and digital collections for long-term institutional preservation.$q$, $q$librarians and digital archivists$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Journalism and research fact-checking archives$q$, $q$Preserving a faithful copy of a web page at a point in time to support reporting or academic research.$q$, $q$journalists and researchers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Open-Source Tools$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["Browser extension and desktop capture with ArchiveWeb.page","Serverless replay with ReplayWeb.page","Self-hostable pywb replay library","No account required for core tools"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Browsertrix Standard$q$, $q$Free for 7 days, then $30/month$q$, $q$Monthly$q$, NULL, $q$["720 minutes of crawl execution time","500GB storage","3 concurrent crawls","Up to 10,000 pages per crawl"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$Browsertrix Custom$q$, $q$Custom$q$, $q$Custom$q$, NULL, $q$["Larger crawl quotas","More storage","Higher concurrency","Dedicated support for organizations"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$overview$q$, $q$What Is Webrecorder$q$, 2, ARRAY[$q$Webrecorder is an open-source project focused on high-fidelity web archiving, tracing back to developer Ilya Kreymer's early browser-based archiving prototypes, which were funded and developed at the nonprofit Rhizome starting in 2016.$q$, $q$In 2020, the project split: the hosted archiving service became Conifer under Rhizome, while Kreymer founded Webrecorder Software LLC in the United States to continue building the underlying open-source tools.$q$, $q$Rather than taking static snapshots, Webrecorder's tools capture pages as they actually behave in a browser, including scripts, video, audio, and interactive elements, so archived copies replay just as the original did.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$ArchiveWeb.page is a browser extension and desktop app that lets anyone capture pages as they browse, while ReplayWeb.page is a browser-based viewer that can replay archived content without needing a server.$q$, $q$Browsertrix is Webrecorder's cloud-based crawling service, designed to archive entire websites at scale for organizations that need automated, high-fidelity captures rather than manual page-by-page recording.$q$, $q$Webrecorder maintains the WACZ file format, an open standard for packaging web archives, along with pywb, a Python library used to power replay for archives created with its tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Webrecorder's core tools, ArchiveWeb.page, ReplayWeb.page, and pywb, are free and open source, and can be self-hosted or run entirely in the browser without an account.$q$, $q$Browsertrix, the hosted crawling service, offers a free trial period before converting to a paid Standard tier priced around 30 dollars per month, which includes several hundred minutes of crawl time, hundreds of gigabytes of storage, and multiple concurrent crawls.$q$, $q$Larger organizations with bigger crawl volumes or dedicated support needs can arrange custom Browsertrix pricing above the Standard tier.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('c3ec637c-da4e-49a1-b2c3-ecb51e556b29', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Visual Canvas with Full CSS Control$q$, $q$Design custom, responsive layouts visually with access to the full range of CSS properties.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Open-Source Core$q$, $q$Core builder code is released under the AGPL-3.0-or-later license and published on GitHub.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Self-Hosting Option$q$, $q$Both the visual editor and the sites built with it can be self-hosted on your own infrastructure.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Headless CMS Integrations$q$, $q$Connects to external content sources such as Strapi, Supabase, Notion, and WordPress instead of forcing a proprietary CMS.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Content Mode$q$, $q$Lets non-technical clients edit page content without altering the underlying design.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Staging Environments with Backups$q$, $q$Supports safer iteration with staging and backup capabilities on paid plans.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Team Workspaces and Roles$q$, $q$Team plan adds shared workspaces, member roles, and multiple included seats.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Code Export$q$, $q$Projects can be shared or exported, supporting portability outside the hosted platform.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Open-source and self-hostable, avoiding the vendor lock-in of closed builders$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Full CSS control similar to Webflow's design depth$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Connects to external headless CMS platforms instead of forcing a proprietary CMS$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Generous free Hobby plan for unlimited projects and pages$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Built by a team with direct Webflow product experience$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Smaller template and integration ecosystem than Webflow$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Self-hosting requires technical setup and ongoing maintenance$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Newer platform with a smaller community and less third-party documentation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Page-view overages on the Pro plan add cost as traffic scales$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Is Webstudio free?$q$, $q$Yes, the Hobby plan is free and includes unlimited projects and pages on a wstd.io subdomain, though a paid plan is needed for a custom domain and more storage.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Is Webstudio really open source?$q$, $q$Yes, its core code is released under the AGPL-3.0-or-later license and published publicly on GitHub.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Can Webstudio be self-hosted?$q$, $q$Yes, because the builder is open source, both the editor and the sites created with it can be self-hosted on your own infrastructure.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$How is Webstudio different from Webflow?$q$, $q$Webstudio offers similar visual design capabilities but is open source and self-hostable, while Webflow is closed-source and only available as a hosted cloud product.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Does Webstudio support headless CMS platforms?$q$, $q$Yes, it connects to external headless CMS sources including Strapi, Supabase, Notion, and WordPress.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$What does the Pro plan include?$q$, $q$Pro, around 15 dollars per month billed yearly, adds custom domains, about 100,000 monthly page views, unlimited form submissions, Content Mode, staging environments, and CMS integrations.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Who built Webstudio?$q$, $q$Webstudio was founded in 2022 by Oleg Isonen, a former Webflow engineer, and is incorporated as Webstudio, Inc. in Dublin, Ireland.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Is Webstudio good for agencies?$q$, $q$It can suit agencies that want Webflow-style design flexibility without vendor lock-in, though its template and integration ecosystem is still smaller than Webflow's.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Open-source alternative to Webflow for agencies$q$, $q$Agencies that want strong visual design control without depending on a single closed-source vendor.$q$, $q$design agencies wanting flexibility without vendor lock-in$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Self-hosted marketing sites for technical teams$q$, $q$Developers who want to host both the builder and the resulting site on their own infrastructure.$q$, $q$developers and technical marketing teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Headless CMS-driven websites$q$, $q$Teams that already manage content in a headless CMS and want a visual front-end builder to match.$q$, $q$teams already using Strapi, Supabase, or Notion as a CMS$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Hobby$q$, $q$$0$q$, $q$Free$q$, NULL, $q$["wstd.io subdomain","Unlimited projects and pages","Project sharing and export","250MB asset storage"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Pro$q$, $q$$15/month billed yearly$q$, $q$Annual$q$, NULL, $q$["Unlimited custom domain sites","~100,000 monthly page views","Unlimited form submissions","Content Mode","Staging environment with backups","CMS integrations","20GB asset storage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$Team$q$, $q$$35/month billed yearly$q$, $q$Annual$q$, NULL, $q$["Everything in Pro","Workspaces","Member roles","5 seats included"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$overview$q$, $q$What Is Webstudio$q$, 2, ARRAY[$q$Webstudio is an open-source, no-code visual website builder founded in 2022 by Oleg Isonen, a former Webflow engineer, and incorporated as Webstudio, Inc. in Dublin, Ireland.$q$, $q$It was built specifically as an open alternative to closed, proprietary no-code builders, offering a visual canvas comparable to Webflow's while releasing its core code under the AGPL-3.0-or-later license on GitHub.$q$, $q$Because the builder itself is open source, both the editor and the sites it produces can be self-hosted on a developer's own infrastructure instead of being locked into a single vendor's cloud.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Webstudio's visual canvas gives designers full control over CSS properties, similar in spirit to Webflow, letting teams build custom, responsive layouts without writing code by hand.$q$, $q$Rather than bundling a proprietary CMS, Webstudio connects to external headless content sources such as Strapi, Supabase, Notion, and WordPress, so teams can manage content independently of the builder.$q$, $q$A Content Mode allows non-technical clients to edit page content safely without touching design, while staging environments with backups support safer iteration for paid plans.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$The free Hobby plan supports unlimited projects and pages on a wstd.io subdomain with 250MB of asset storage, useful for personal projects or evaluation.$q$, $q$The Pro plan, around 15 dollars per month billed yearly, adds custom domains, roughly 100,000 monthly page views, unlimited form submissions, Content Mode, staging environments, and CMS integrations, with 20GB of asset storage.$q$, $q$The Team plan, around 35 dollars per month billed yearly, includes everything in Pro plus workspaces, member roles, and five included seats, and because the core is open source, technical teams can also self-host instead of paying for hosted plans at all.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('17c0bc49-5c4a-433c-9ace-21a7b1f6192b', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Local, Self-Hosted Smart Home Hub$q$, $q$Runs entirely on your own hardware, keeping device control and data local by default.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Web of Things Standard Compliance$q$, $q$Implements the W3C Web of Things standard so different device types share one consistent interface.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Add-on Ecosystem$q$, $q$Community-built add-ons bridge protocols including Zigbee, Z-Wave, and Philips Hue into the gateway.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Rules Engine for Automation$q$, $q$Lets users define if-this-then-that style automation rules between connected devices.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Device Grouping$q$, $q$Added in version 2.0, lets users drag and drop devices into organizational groups.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Privacy-First Design$q$, $q$Does not require a mandatory third-party cloud account to operate the gateway locally.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Secure Remote Access$q$, $q$An optional service, sponsored by Krellian, provides remote access to a gateway without complex networking setup.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Multi-Language Interface$q$, $q$The gateway software has been translated into dozens of languages by its community.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Free and fully open source, with no subscription required$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Keeps smart home data local and private by default$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Standards-based on the Web of Things rather than tied to one vendor's ecosystem$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Backed by an active community and now maintained by Krellian following its spin-out from Mozilla$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Broad device support through community-built add-ons$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Requires self-hosting on hardware like a Raspberry Pi, with more setup than plug-and-play hubs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Smaller device compatibility ecosystem than Google Home, Alexa, or SmartThings$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Community-maintained project means slower feature velocity than well-funded commercial competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Less consumer-friendly onboarding and support than retail smart home products$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Is WebThings Gateway free?$q$, $q$Yes, it is completely free and open source, with the only real cost being the hardware you run it on.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$What hardware do I need to run WebThings Gateway?$q$, $q$It is most commonly installed on a Raspberry Pi, though it can run on other compatible hardware as well.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Is WebThings Gateway still maintained after Mozilla left the project?$q$, $q$Yes, it became an independent, community-led open-source project in December 2020, with Krellian sponsoring the website and cloud infrastructure, and it received a 2.0 release in December 2025.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$What is the Web of Things standard?$q$, $q$It is a W3C standard that WebThings Gateway implements so devices from different manufacturers can be controlled through one consistent web-based interface.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Does WebThings Gateway require a cloud account?$q$, $q$No, the core gateway runs locally without a mandatory cloud account; a cloud-based remote access feature is optional.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$What devices does WebThings Gateway support?$q$, $q$Support depends on installed add-ons, which bridge protocols such as Zigbee, Z-Wave, and Philips Hue into the gateway.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$How is WebThings Gateway different from Home Assistant?$q$, $q$Both are open-source, self-hosted smart home platforms; WebThings Gateway is built specifically around the W3C Web of Things standard and originated at Mozilla, while Home Assistant has a broader independent integration ecosystem.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$What is new in WebThings Gateway 2.0?$q$, $q$Version 2.0, released in December 2025, added a groups feature that lets users organize devices by dragging and dropping them into groups.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Privacy-focused home automation$q$, $q$Running smart home automation entirely on local hardware without sending data to a third-party cloud.$q$, $q$privacy-conscious homeowners and makers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$DIY Raspberry Pi smart hubs$q$, $q$Building a personal, low-cost IoT gateway on a Raspberry Pi for home projects.$q$, $q$hobbyists and IoT tinkerers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Standards-based small-scale building automation$q$, $q$Experimenting with or deploying Web of Things standards for small organizational or building automation projects.$q$, $q$small organizations and developers experimenting with the Web of Things$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$Open Source$q$, $q$Free$q$, $q$Free$q$, NULL, $q$["Self-hosted gateway software","Local dashboard and rules engine","Community add-ons for device protocols","Optional secure remote access via Krellian"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$overview$q$, $q$What Is WebThings Gateway$q$, 2, ARRAY[$q$WebThings Gateway is open-source software for running your own private smart home or IoT hub, most commonly installed on a Raspberry Pi, that started life inside Mozilla in 2017 as Project Things.$q$, $q$The project was built around the idea of applying Mozilla's privacy-focused, open-web philosophy to the Internet of Things, implementing the Web of Things standard so devices from different manufacturers can be controlled through one consistent interface.$q$, $q$In December 2020, Mozilla spun the project out as an independent, community-led open-source effort, with UK-based Krellian, founded by former Mozilla and Google engineer Ben Francis, sponsoring the website and cloud infrastructure that keeps gateways updated and reachable remotely.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The gateway provides a local dashboard for monitoring sensors, controlling lights, switches, and other connected devices, and defining automation rules, all running on hardware you control.$q$, $q$A large community add-on ecosystem, with more than a hundred add-ons at the project's peak, bridges protocols such as Zigbee, Z-Wave, and Philips Hue into the standardized Web of Things interface.$q$, $q$WebThings Gateway 2.0, released in December 2025, added a groups feature that lets users drag and drop devices into organizational groups for easier management.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$WebThings Gateway is completely free and open source; there is no subscription fee to download, install, or run the software.$q$, $q$Users do need their own hardware, typically a Raspberry Pi, to host the gateway, which represents the main real-world cost of adoption.$q$, $q$An optional secure remote access service, sponsored by Krellian, allows access to a gateway from outside the local network without requiring complex router configuration.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('e3732b36-1f7f-4598-84f0-2ab858cfea63', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
