-- ── Webhook.site ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Webhook.site is a free developer tool that instantly generates a unique URL and email address so you can inspect, log, and debug incoming HTTP requests, webhooks, and emails in real time.$q$, short_description),
  pricing_model = COALESCE($q$freemium$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(NULL, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Webhook.site Review: Features, Pricing, and How It Works$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Webhook.site lets developers test and debug webhooks and HTTP requests for free, plus its Pro and Enterprise pricing and open-source self-hosted option.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Webhook.site is a free, developer-focused utility for testing, inspecting, and debugging incoming HTTP requests, webhooks, and emails. Built by developer Simon Fredsted using Laravel for the backend API and Angular.js for the frontend, the tool is also released as an open-source, MIT-licensed project on GitHub that can be self-hosted with Docker, in addition to the hosted cloud version at webhook.site. The core workflow is simple: visiting the site instantly generates a unique, disposable URL and a matching email address; any HTTP request sent to that URL, or any email sent to that address, is captured and displayed in a live, browser-based inspector showing headers, body, query parameters, and timing. This makes it a common first stop for developers integrating with services that send webhooks, such as Stripe, GitHub, or Shopify, since it removes the need to spin up a local server or use tunneling tools just to see what a webhook payload looks like. Beyond basic inspection, Webhook.site supports configuring custom responses, including status codes, headers, and bodies, so a URL can simulate a real API endpoint during testing, and its Pro tier adds Custom Actions, a scripting feature that lets users transform, forward, or react to incoming requests programmatically, effectively turning a test URL into a lightweight webhook processing pipeline. On the free plan, each URL is limited to 50 stored requests and is automatically deleted after 7 days, which is sufficient for quick, one-off debugging but not for long-running integrations or team use. The paid Pro plan, priced at 27 dollars per month or 270 dollars per year, raises those limits substantially, adds Custom Actions, CSV export, and URLs that no longer expire, while the Enterprise plan, at 69 dollars per month or 699 dollars per year, adds custom domain support, SAML single sign-on, multi-user support, and a much larger request history. Webhook.site competes with tools like Beeceptor and Hookdeck, but is generally regarded as one of the fastest and simplest options for ad hoc webhook inspection, especially given its no-signup free tier and open-source self-hosting option for teams with data-residency requirements.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f5c5646b-b55a-44bf-ba99-9b66ef0e4eb8';

