-- ── Webrecorder ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Webrecorder is an open-source suite of web archiving tools, including ArchiveWeb.page, Browsertrix, and ReplayWeb.page, that lets anyone capture, verify, and replay interactive copies of web pages.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free (open-source tools); Browsertrix Cloud hosting from $30/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Webrecorder Review: Open-Source Web Archiving Tools and Pricing$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how Webrecorder's open-source tools, ArchiveWeb.page, Browsertrix, and ReplayWeb.page, capture and replay interactive web archives, plus Browsertrix Cloud pricing.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Webrecorder is an open-source project and small technology company dedicated to building tools for high-fidelity web archiving. Its origins trace back to developer Ilya Kreymer's early browser-based archiving prototypes, which were adopted and funded starting in 2016 by Rhizome, a New York-based digital arts nonprofit, through a multi-year grant from the Andrew W. Mellon Foundation. After several years of development under Rhizome, the project split in 2020: the hosted archiving service was renamed Conifer and remained with Rhizome, while Kreymer founded the independent Webrecorder Software LLC, based in the United States, to continue developing the underlying open-source tools. Unlike traditional web archiving approaches such as simple HTML scraping or crawl-based snapshots, Webrecorder's tools focus on capturing pages as they actually behave when browsed, including JavaScript-rendered content, video and audio playback, scrolling, and interactive elements, producing archives that can be faithfully replayed later even if the original site changes or disappears. The toolset includes ArchiveWeb.page, a browser extension and desktop app for capturing pages as you browse them; ReplayWeb.page, a browser-based viewer for replaying archived content without needing a server; pywb, a Python library for web archive replay; and Browsertrix, a cloud-based, high-fidelity crawling service for archiving entire websites at scale, aimed at libraries, archives, researchers, and organizations with compliance or legal-hold needs. Webrecorder also maintains and champions the WACZ file format, an open standard for packaging and sharing web archives. Most of Webrecorder's tools, including ArchiveWeb.page and ReplayWeb.page, are free and open source and can be self-hosted or run entirely client-side in a browser. Browsertrix, the hosted crawling service, offers a free multi-day trial followed by paid plans starting around 30 dollars per month for a standard tier that includes several hundred minutes of crawl execution time, hundreds of gigabytes of storage, multiple concurrent crawls, and per-crawl page limits, with higher tiers and custom plans available for larger archiving programs. Webrecorder is widely used by librarians, digital preservationists, journalists, researchers, and legal teams who need to capture an authentic, interactive record of a web page for evidence, research, or long-term preservation, positioning it as a specialized, standards-based alternative to generic screenshot tools or crawl-based archives.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'c3ec637c-da4e-49a1-b2c3-ecb51e556b29';

