-- ── WebThings Gateway ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$WebThings Gateway is a free, open-source smart home hub software that lets you self-host a private, local Internet of Things gateway for monitoring and controlling connected devices without depending on a manufacturer's cloud.$q$, short_description),
  pricing_model = COALESCE($q$open-source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$WebThings Gateway Review: Open-Source Smart Home Hub$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how WebThings Gateway, the open-source IoT hub originally built by Mozilla, lets you self-host a private smart home gateway, plus its features and add-ons.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$WebThings Gateway is a free, open-source software distribution for building a self-hosted smart home or IoT gateway, focused on privacy, security, and interoperability rather than tying users to a single manufacturer's cloud service. The project originated inside Mozilla as Project Things, first released in June 2017 following an internal whitepaper exploring how Mozilla's mission around user privacy and an open web could extend to the emerging Internet of Things ecosystem. Over roughly four years of development at Mozilla, the project evolved into the WebThings platform, combining the WebThings Framework, for implementing the Web of Things standard on devices, with the WebThings Gateway, the hub application end users run, typically on a Raspberry Pi or similar hardware. By the time of its 1.0 release, WebThings Gateway had been translated into around 34 languages, downloaded over 100,000 times, and supported by more than a hundred community-built add-ons that bridge protocols like Zigbee, Z-Wave, and Philips Hue into a single standardized web-based interface. In December 2020, Mozilla spun the project out of its own umbrella, and WebThings became an independent, community-led open-source project with its own home at webthings.io; UK-based company Krellian, founded in 2020 by former Mozilla and Google engineer Ben Francis, took on sponsorship of the WebThings website and cloud infrastructure, including automatic software updates and a secure remote access service for gateways. Because it is free and open source, WebThings Gateway can be installed on your own hardware, most commonly a Raspberry Pi, and gives users a local dashboard for monitoring sensors, controlling lights and switches, defining automation rules, and grouping devices, all without sending data to a third-party cloud unless the user explicitly opts into a remote access feature. In December 2025, the project shipped WebThings Gateway 2.0, adding a widely requested groups feature that lets users drag and drop devices into organizational groups. WebThings Gateway is best suited for privacy-conscious hobbyists, makers, and small organizations who want an open, standards-based alternative to closed ecosystems like Google Home, Amazon Alexa, or Samsung SmartThings, and who are comfortable with some self-hosting and hardware setup. It is not a polished consumer product sold through retail channels, but rather a community-maintained open-source project distributed as free software.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'e3732b36-1f7f-4598-84f0-2ab858cfea63';

